async (page) => {
  // Known Oak positions from earlier observation
  const oakPositions = [
    {x: 206, y: 118},
    {x: 219, y: 112},
    {x: 225, y: 117},
    {x: 213, y: 133},
    {x: 205, y: 131},
  ];

  let totalLogs = await page.evaluate(() => {
    const inv = window.__latestGameState?.inventory || [];
    return inv.filter(i => i.name === 'Logs').reduce((s, i) => s + i.count, 0);
  });

  for (const oak of oakPositions) {
    if (totalLogs >= 10) break;

    // Walk adjacent to Oak
    await page.evaluate((pos) => JSON.stringify(window.__clickTile(pos.x, pos.y)), oak);
    await page.waitForTimeout(3500);

    // Find Oak near those coords and click it
    const oakLabel = await page.evaluate((target) => {
      const m = window.__latestAsciiMap;
      if (!m || m.error) return null;
      const lines = m.legendText.split('\n');
      // Try exact match first
      for (const line of lines) {
        if (line.includes('Oak') && line.includes('(' + target.x + ',' + target.y + ')')) {
          const match = line.match(/(E\d+)/);
          if (match) return match[1];
        }
      }
      // Fallback: closest oak at dist <= 2
      for (const line of lines) {
        if (line.includes('[^] Oak')) {
          const distMatch = line.match(/dist=(\d+)/);
          if (distMatch && parseInt(distMatch[1]) <= 2) {
            const labelMatch = line.match(/(E\d+)/);
            if (labelMatch) return labelMatch[1];
          }
        }
      }
      return null;
    }, oak);

    if (oakLabel) {
      await page.evaluate((label) => window.__clickEntity(label), oakLabel);
      await page.waitForTimeout(5000);

      totalLogs = await page.evaluate(() => {
        const inv = window.__latestGameState?.inventory || [];
        return inv.filter(i => i.name === 'Logs').reduce((s, i) => s + i.count, 0);
      });
    }
  }

  const inv = await page.evaluate(() => window.__latestGameState?.inventory?.map(i => ({name: i.name, count: i.count})));
  const pos = await page.evaluate(() => window.__latestGameState?.player_position);
  return JSON.stringify({totalLogs, inventory: inv, pos});
}

