async (page) => {
  // Get the current map and chop the nearest oak
  async function chopNearestOak() {
    const data = await page.evaluate(() => {
      const entities = window.__latestGameState?.nearby_entities || [];
      // Find nearest on-screen Oak
      for (const e of entities) {
        if (e.name === 'Oak' && e.on_screen && e.click_x && e.click_y) {
          return {found: true, id: e.id, x: e.x, y: e.y, dist: e.distance, cx: e.click_x, cy: e.click_y};
        }
      }
      // Find nearest off-screen Oak to walk toward
      for (const e of entities) {
        if (e.name === 'Oak') {
          return {found: true, id: e.id, x: e.x, y: e.y, dist: e.distance, offscreen: true};
        }
      }
      return {found: false};
    });
    return data;
  }

  let logs = 3;
  const results = [];

  for (let attempt = 0; attempt < 12 && logs < 10; attempt++) {
    const oak = await chopNearestOak();
    if (!oak.found) {
      results.push('No oak found, waiting...');
      await page.waitForTimeout(5000);
      continue;
    }

    if (oak.offscreen) {
      // Walk toward it
      await page.evaluate((pos) => window.__clickTile(pos.x, pos.y), {x: oak.x, y: oak.y});
      await page.waitForTimeout(4000);
    }

    // Click the oak using canvas dispatch
    await page.evaluate(({cx, cy}) => {
      const canvas = document.getElementById('canvas');
      canvas.dispatchEvent(new MouseEvent('click', { clientX: cx, clientY: cy, bubbles: true, ctrlKey: false }));
    }, {cx: oak.cx || 600, cy: oak.cy || 400});
    await page.waitForTimeout(5000);

    logs = await page.evaluate(() => {
      return (window.__latestGameState?.inventory || [])
        .filter(i => i.name === 'Logs').reduce((s, i) => s + i.count, 0);
    });
    results.push({attempt, oak_pos: {x: oak.x, y: oak.y}, logs});
  }

  const inv = await page.evaluate(() => window.__latestGameState?.inventory?.map(i => ({name: i.name, count: i.count})));
  const pos = await page.evaluate(() => window.__latestGameState?.player_position);
  return JSON.stringify({logs, pos, inv, results});
}

async (page) => {
  let logs = 5;
  const choppedIds = [];

  for (let attempt = 0; attempt < 20 && logs < 10; attempt++) {
    // Get fresh oak data - prefer unvisited on-screen oaks
    const oak = await page.evaluate((skipIds) => {
      const entities = window.__latestGameState?.nearby_entities || [];
      // First: closest on-screen unvisited oak
      for (const e of entities) {
        if (e.name === 'Oak' && e.on_screen && e.click_x && !skipIds.includes(e.id)) {
          return {id: e.id, x: e.x, y: e.y, dist: e.distance, cx: e.click_x, cy: e.click_y};
        }
      }
      // Second: any on-screen oak
      for (const e of entities) {
        if (e.name === 'Oak' && e.on_screen && e.click_x) {
          return {id: e.id, x: e.x, y: e.y, dist: e.distance, cx: e.click_x, cy: e.click_y};
        }
      }
      // Third: off-screen oak to walk to
      for (const e of entities) {
        if (e.name === 'Oak' && !skipIds.includes(e.id)) {
          return {id: e.id, x: e.x, y: e.y, dist: e.distance, offscreen: true};
        }
      }
      return null;
    }, choppedIds);

    if (!oak) {
      await page.waitForTimeout(3000);
      continue;
    }

    if (oak.offscreen) {
      await page.evaluate((pos) => window.__clickTile(pos.x, pos.y), {x: oak.x, y: oak.y});
      await page.waitForTimeout(4000);
      continue;
    }

    // Walk closer if needed
    if (oak.dist > 3) {
      await page.evaluate((pos) => window.__clickTile(pos.x, pos.y), {x: oak.x, y: oak.y});
      await page.waitForTimeout(3000);
    }

    // Click the tree
    const freshOak = await page.evaluate((target) => {
      const entities = window.__latestGameState?.nearby_entities || [];
      const e = entities.find(en => en.id === target.id);
      return e && e.click_x ? {cx: e.click_x, cy: e.click_y} : target;
    }, {id: oak.id, cx: oak.cx, cy: oak.cy});

    await page.evaluate(({cx, cy}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', {clientX: cx, clientY: cy, bubbles: true, ctrlKey: false}));
    }, freshOak);
    await page.waitForTimeout(5000);

    if (!choppedIds.includes(oak.id)) choppedIds.push(oak.id);

    logs = await page.evaluate(() => 
      (window.__latestGameState?.inventory || []).filter(i => i.name === 'Logs').reduce((s, i) => s + i.count, 0)
    );
  }

  const inv = await page.evaluate(() => window.__latestGameState?.inventory?.map(i => ({name: i.name, count: i.count})));
  const pos = await page.evaluate(() => window.__latestGameState?.player_position);
  return JSON.stringify({logs, pos, inv});
}

