async (page) => {
  let kills = 0;

  for (let i = 0; i < 20; i++) {
    // Find nearest mob
    const mob = await page.evaluate(() => {
      const entities = window.__latestGameState?.nearby_entities || [];
      // Prefer rats (easy), then batterflies
      for (const e of entities) {
        if (e.type === 3 && (e.name === 'Rat') && e.on_screen && e.click_x) {
          return {label: null, id: e.id, name: e.name, x: e.x, y: e.y, hp: e.hp, dist: e.distance, cx: e.click_x, cy: e.click_y};
        }
      }
      // Any mob on screen
      for (const e of entities) {
        if (e.type === 3 && e.on_screen && e.click_x) {
          return {label: null, id: e.id, name: e.name, x: e.x, y: e.y, hp: e.hp, dist: e.distance, cx: e.click_x, cy: e.click_y};
        }
      }
      // Off-screen mob
      for (const e of entities) {
        if (e.type === 3) return {id: e.id, name: e.name, x: e.x, y: e.y, offscreen: true};
      }
      return null;
    });

    if (!mob) { await page.waitForTimeout(3000); continue; }

    if (mob.offscreen) {
      await page.evaluate((p) => window.__clickTile(p.x, p.y), mob);
      await page.waitForTimeout(3000);
      continue;
    }

    // Attack the mob
    await page.evaluate(({cx, cy}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', {clientX: cx, clientY: cy, bubbles: true, ctrlKey: false}));
    }, mob);
    await page.waitForTimeout(7000); // wait for combat

    // Check if mob died (HP = 0 or not found)
    const mobDead = await page.evaluate((id) => {
      const e = (window.__latestGameState?.nearby_entities || []).find(e => e.id === id);
      return !e || e.hp === 0;
    }, mob.id);

    if (mobDead) kills++;

    // Check our HP
    const hp = await page.evaluate(() => {
      const s = window.__latestGameState?.player_stats;
      return {hp: s?.hp, max: s?.max_hp};
    });

    if (hp.hp < hp.max * 0.4) {
      // Eat food if available
      const food = await page.evaluate(() => {
        return (window.__latestGameState?.inventory || []).find(i => i.edible);
      });
      if (food) {
        await page.evaluate((slot) => window.game.menu.getInventory().selectEdible(slot), food.slot);
        await page.waitForTimeout(1000);
      } else {
        // Walk away and wait to regen
        await page.waitForTimeout(5000);
      }
    }

    // Check strength level
    const strength = await page.evaluate(() => {
      const skills = window.game?.player?.skills;
      return skills?.[6]?.level;
    });

    if (strength >= 10) return 'Strength 10 reached! Kills: ' + kills;
  }

  const strength = await page.evaluate(() => window.game?.player?.skills?.[6]?.level);
  const pos = await page.evaluate(() => window.__latestGameState?.player_position);
  return JSON.stringify({kills, strength, pos});
}

async (page) => {
  let kills = 7;
  let strengthLevel = 5;

  while (strengthLevel < 10) {
    // Get fresh mob data
    const mob = await page.evaluate(() => {
      const entities = window.__latestGameState?.nearby_entities || [];
      // Best: rat on screen
      for (const e of entities) {
        if (e.type === 3 && e.name === 'Rat' && e.on_screen && e.click_x && e.hp > 0)
          return {id: e.id, name: e.name, x: e.x, y: e.y, cx: e.click_x, cy: e.click_y, dist: e.distance};
      }
      // Any mob on screen
      for (const e of entities) {
        if (e.type === 3 && e.on_screen && e.click_x && e.hp > 0)
          return {id: e.id, name: e.name, x: e.x, y: e.y, cx: e.click_x, cy: e.click_y, dist: e.distance};
      }
      // Off-screen mob to walk toward
      for (const e of entities) {
        if (e.type === 3 && e.hp > 0) return {id: e.id, name: e.name, x: e.x, y: e.y, offscreen: true};
      }
      return null;
    });

    if (!mob) {
      await page.waitForTimeout(4000);
      continue;
    }

    if (mob.offscreen) {
      await page.evaluate((p) => window.__clickTile(p.x, p.y), mob);
      await page.waitForTimeout(4000);
      continue;
    }

    // Attack
    await page.evaluate(({cx, cy}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', {clientX: cx, clientY: cy, bubbles: true, ctrlKey: false}));
    }, mob);
    await page.waitForTimeout(8000);

    const dead = await page.evaluate((id) => {
      const e = (window.__latestGameState?.nearby_entities || []).find(e => e.id === id);
      return !e || e.hp === 0;
    }, mob.id);
    if (dead) kills++;

    // Heal if needed
    const hp = await page.evaluate(() => {
      const s = window.__latestGameState?.player_stats;
      return {hp: s?.hp, max: s?.max_hp};
    });
    if (hp.hp < hp.max * 0.4) {
      const food = await page.evaluate(() => (window.__latestGameState?.inventory || []).find(i => i.edible));
      if (food) {
        await page.evaluate((slot) => window.game.menu.getInventory().selectEdible(slot), food.slot);
        await page.waitForTimeout(1000);
      } else {
        await page.waitForTimeout(10000); // passive regen
      }
    }

    strengthLevel = await page.evaluate(() => window.game?.player?.skills?.[6]?.level || 0);

    // Safety: stop if too many kills to prevent infinite loop
    if (kills > 60) break;
  }

  const pos = await page.evaluate(() => window.__latestGameState?.player_position);
  const stats = await page.evaluate(() => window.__latestGameState?.player_stats);
  return JSON.stringify({kills, strengthLevel, pos, hp: stats?.hp + '/' + stats?.max_hp});
}

